update public.portfolio_projects
set
  title_en = $$Monarch Mansion Galati$$,
  badge_label_en = $$Facade Lighting$$,
  portfolio_description_en = $$The project focused on defining the building volumes and highlighting decorative elements through a carefully positioned architectural lighting system. The result is a facade with depth and character.$$,
  main_description_en = $$The project focused on defining the building volumes and highlighting decorative elements through a carefully positioned architectural lighting system. The result is a facade with depth and character.$$,
  site_title_en = $$From Site to Reality$$,
  site_description_en = $$This project highlights the power of lighting to completely transform the perception of an outdoor space, enhancing the architecture, access paths, and surrounding natural elements. Through a carefully planned intervention, the original ambience was redefined into a balanced, warm, and refined lighting composition. The new lighting system adds depth, safety, and character, creating a welcoming and sophisticated atmosphere where aesthetics and functionality work together harmoniously.$$
where id = '5914629b-593c-42a3-89b9-2b86cb3b07de';

update public.portfolio_projects
set
  title_en = $$Izvorul Rece Museum$$,
  badge_label_en = $$Indoor Lighting$$,
  portfolio_description_en = $$An interior lighting project carried out in an exhibition space with a distinct personality, where light is used to showcase the artworks, room volumes, and calm atmosphere of the museum. The proposed solution aims for a balance between accent, depth, and visual comfort, so each area can be perceived naturally without overwhelming the existing architecture.$$,
  main_description_en = $$An interior lighting project carried out in an exhibition space with a distinct personality, where light is used to showcase the artworks, room volumes, and calm atmosphere of the museum. The proposed solution aims for a balance between accent, depth, and visual comfort, so each area can be perceived naturally without overwhelming the existing architecture.$$,
  site_title_en = $$From Site to Reality$$,
  site_description_en = $$The implementation focused on carefully integrating the lighting systems into the existing architecture, with emphasis on exhibition areas, gallery walls, and central objects within the space. The result is a balanced ambience where each artwork receives the right visibility, while the museum preserves its refined and quiet atmosphere.$$
where id = 'c22acc12-990f-49ce-a2bc-da4f666503cf';

update public.portfolio_projects
set
  title_en = $$The North Face - AFI Cotroceni$$,
  badge_label_en = $$Retail Lighting$$,
  portfolio_description_en = $$A retail lighting project created to support the strong identity of The North Face brand through a modern, technical, and well-controlled atmosphere. The lighting enhances the products, display routes, and materials used in the fit-out, contributing to a clear, premium, and exploration-oriented visual experience.$$,
  main_description_en = $$A retail lighting project created to support the strong identity of The North Face brand through a modern, technical, and well-controlled atmosphere. The lighting enhances the products, display routes, and materials used in the fit-out, contributing to a clear, premium, and exploration-oriented visual experience.$$,
  site_title_en = $$From Site to Reality$$,
  site_description_en = $$The fit-out started from a well-defined retail concept in which every area needed to be clear, easy to navigate, and visually coherent. Through the careful positioning of lighting fixtures, the products were highlighted without overcrowding the space, while brand elements, shelving, display areas, and the storefront received lighting adapted to their role in the shopping experience.$$
where id = '20666d70-7e44-4a00-8bae-01e4a37b0878';

update public.portfolio_projects
set
  title_en = $$Residential Apartment$$,
  badge_label_en = $$Residential Lighting$$,
  portfolio_description_en = $$A residential lighting project created for a modern apartment, with emphasis on atmosphere, visual comfort, and discreet integration into the interior architecture. The lighting solutions were designed to highlight the clean lines of the space, wall textures, minimalist furniture, and relaxation areas without visually overloading the design.$$,
  main_description_en = $$A residential lighting project created for a modern apartment, with emphasis on atmosphere, visual comfort, and discreet integration into the interior architecture. The lighting solutions were designed to highlight the clean lines of the space, wall textures, minimalist furniture, and relaxation areas without visually overloading the design.$$,
  site_title_en = $$From Site to Reality$$,
  site_description_en = $$The project started from the need to preserve a clean and airy design, where every light source had a clear purpose. Indirect lighting was integrated into circulation areas and architectural details, while spotlights and magnetic tracks were used for directional light and flexibility. The result is a coherent, modern, and welcoming apartment where light completes the interior design without becoming intrusive.$$
where id = 'c487a9d4-fba6-4eea-a3ad-7316b79f4e6d';

update public.portfolio_projects
set
  title_en = $$Piata Unirii Office$$,
  badge_label_en = $$Office Lighting$$,
  portfolio_description_en = $$A lighting project for a modern office space in the Piata Unirii area, where light was integrated directly into the ceiling architecture. The proposed solution emphasizes clean lines, directional light, and a technical look, perfectly suited to a contemporary interior under development.$$,
  main_description_en = $$A lighting project for a modern office space in the Piata Unirii area, where light was integrated directly into the ceiling architecture. The proposed solution emphasizes clean lines, directional light, and a technical look, perfectly suited to a contemporary interior under development.$$,
  site_title_en = $$From Site to Reality$$,
  site_description_en = $$The installation was carried out at a stage when the space was already shaping its final identity. The lighting tracks were positioned to follow the geometry of the ceiling and support the main work, circulation, and accent areas. The result is a technical, discreet, and coherent solution that transforms the ceiling into an important visual element of the design.$$
where id = '7763f9c5-b146-4f16-af14-09832abe8a29';

update public.portfolio_projects
set
  title_en = $$City Gate$$,
  badge_label_en = $$Office Lighting$$,
  portfolio_description_en = $$An architectural lighting project for the reception and lobby area of the City Gate building, where light was used to emphasize the elegance of the materials, the modern lines of the space, and the sense of depth. The proposed solution supports a premium, clear, and representative atmosphere for a high-impact corporate space.$$,
  main_description_en = $$An architectural lighting project for the reception and lobby area of the City Gate building, where light was used to emphasize the elegance of the materials, the modern lines of the space, and the sense of depth. The proposed solution supports a premium, clear, and representative atmosphere for a high-impact corporate space.$$,
  site_title_en = $$From Site to Reality$$,
  site_description_en = $$The project aimed to integrate lighting discreetly into the existing architecture without visually overloading the space. Linear fixtures were positioned to guide circulation routes, while vertical accents were used to mark important areas and add depth to the walls. The result is a coherent, bright, and elegant lobby where every lighting element contributes to the final image of the building.$$
where id = '75d2b664-26c4-45e0-b048-8f872c23cf27';

update public.portfolio_projects
set
  title_en = $$KAO$$,
  badge_label_en = $$Restaurant Lighting$$,
  portfolio_description_en = $$A decorative and architectural lighting project for a restaurant with a strong visual identity, where light contributes directly to the atmosphere, experience, and perception of the space. The selected solutions highlight the oriental details, rich textures, dining areas, and bar, creating a warm, spectacular, and memorable ambience.$$,
  main_description_en = $$A decorative and architectural lighting project for a restaurant with a strong visual identity, where light contributes directly to the atmosphere, experience, and perception of the space. The selected solutions highlight the oriental details, rich textures, dining areas, and bar, creating a warm, spectacular, and memorable ambience.$$,
  site_title_en = $$From Site to Reality$$,
  site_description_en = $$The project involved carefully integrating the lighting into the already defined design details, so each area would receive the right light without losing its atmosphere. Light lines were used to outline walls and steps, decorative fixtures added visual rhythm, and accent lighting highlighted key areas. The result is a coherent, warm, and expressive interior where light becomes part of the restaurant's story.$$
where id = '62219eab-d74b-42f4-a909-245999db6988';
